var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khh...!","TWN":"咳……！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"도망칠 곳도 없고, 최악이네.","JPN":"逃げ場もないし、最悪。","ENG":"This is the worst. I've got nowhere to run.","TWN":"無處可逃，太糟糕了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야? 어디가?","JPN":"ん？　どこ行くんだ？","ENG":"Huh? Where do you think you're going?","TWN":"怎麼回事？你去哪？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"날 처리하러 온 거 아니었어?","JPN":"あたしを始末しに来たんじゃないの？","ENG":"Aren't you here to kill me?","TWN":"不是來殺我的嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소린지 하나도 못 알아듣겠군.","JPN":"さっきから何を言ってるんだ？","ENG":"I have no idea what you're talking about.","TWN":"我完全聽不懂你在說什麼。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 분명 리플레이서 놈들이 활개칠 때 죽었던 게 아니었나?","JPN":"貴様は確か、リプレイサーの奴らが暴れていた時に死んだのではなかったのか？","ENG":"I thought you died when those Replacers ran amok.","TWN":"你在克隆集團那一次事件中不是早就死了嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐…? 거기서부터 아무것도 몰랐다고?","JPN":"は……？　あの後のこと、何も知らないの？","ENG":"What...? That's the last thing you know?","TWN":"什麼……？你對那以後的事情毫不知情？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래, 네 녀석이 나유빈과 어울리고 다녔다는 얘기도 처음 듣는다.","JPN":"ああ、貴様がイチノセ・カオルと付き合っていたという話も初耳だ。","ENG":"Yes. And this is the first time I'm hearing that you were hanging out with Na Yubin.","TWN":"沒錯，我還第一次聽說了你和羅瑜斌一起行動。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 클리포트게임이 한 차례 끝난 이상, 육익이든 범죄자든 내가 널 당장 처리할 의무 같은 건 없어.","JPN":"それから、クリフォトゲームが一度終わった以上、六翼だろうが犯罪者だろうが私が今すぐ貴様を始末する理由はない。","ENG":"Furthermore, since the Qliphoth Game is already done with, I have no obligation to get rid of you right away, even if you're Six Wings or a criminal.","TWN":"既然逆卡巴拉遊戲已經告一段落，我現在也沒有義務殺掉你，不管你是六翼還是囚犯。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어…….","JPN":"えっ……？","ENG":"Oh...","TWN":"喔……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"살아있는 건 둘째 치고, 그 녀석이 지금 네 꼬라지를 보면 적잖이 충격을 받겠어.","JPN":"あいつが今の貴様の姿を見ればショックを受けるだろうな。","ENG":"Aside from being alive, that kid would be shocked if she could see you right now.","TWN":"先不說你還活著，如果她看到你現在這副樣子一定會很受打擊吧。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳 중죄수들은 너처럼 흉물스런 옷을 입고 다니는 형벌이라도 받는 건가?","JPN":"ここの重罪人は、みんな貴様のような醜い服を着る刑罰でも受けているのか？","ENG":"Is it the felons' punishment to wear something so hideous?","TWN":"這裡的其他重犯也要和你一樣穿上如此奇怪的衣服嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"패션이거든?","JPN":"ファッションだよ。わからない？","ENG":"It's called fashion.","TWN":"這可是時尚，懂嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아… 적이 아니라는 건 미리 좀 알려주면 좋았잖아.","JPN":"はあ……敵じゃないなら先に言ってよね。","ENG":"*Sigh...* You could've told me you weren't an enemy.","TWN":"唉……怎麼不早點告訴我不是敵人。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다짜고짜 덤벼 놓고 뻔뻔하군.","JPN":"かかってきたのは貴様だろう。","ENG":"You're the one who jumped at me.","TWN":"明明是你先出手的，真是厚臉皮。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"저기…","JPN":"あの……","ENG":"Excuse me...","TWN":"那個……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"듣자 하니 더이상 서로 싸울 이유는 없는 것 같은데, 화해하고 떨어지시는 게 어떨까요?","JPN":"もうケンカする理由はないようなので、仲直りして離れるのはどうですか？","ENG":"Sounds like you two have no reason to be fighting. Perhaps you can make peace and step back from each other.","TWN":"我們似乎沒有理由相互爭吵了，要不就此和解後道別吧？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"야, 가이드. 그럼 넌 왜 이 여자한테 협력하고 있던 거야?","JPN":"おい、ガイド。じゃあ、あんたはなんでこの女に協力してたんだ？","ENG":"Hey, guide. Why are you helping this woman?","TWN":"喂，小幫手。你為什麼在幫助這個女人？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"제 실력으론 이 분을 이길 수 없거든요.","JPN":"僕の実力ではこの方に勝てませんから。","ENG":"Because I can't beat her.","TWN":"因為憑我的實力沒辦法打敗她。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아? 뭔 소린지 전혀 모르겠는데?","JPN":"はあ？　何のことか全然わかんないけど。","ENG":"Hah? I don't get it.","TWN":"啊？完全聽不明白？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"죄수가 난동을 피운 이상, 아케론의 교도관들은 목숨을 걸고 이 사람을 막으려 하겠죠.","JPN":"囚人が騒動を起こした以上、アケロンの刑務官は命をかけてこの人を止めようとするでしょう。","ENG":"Since a prisoner caused a disturbance, the officers of Acheron are going to risk their lives to stop her.","TWN":"既然囚犯鬧事，黃泉獄警們一定會拿出性命阻止這個人。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"무고한 사람들이 피해를 보는 걸 막으려면 싸움을 피할 수 있도록 협조하는 편이 저에겐 최선이었습니다.","JPN":"罪のない人たちに迷惑がかかるのを防ぐには、戦いを回避できるよう協力するのがベストだったんです。","ENG":"My best option was to assist her in order to prevent innocent people from being harmed.","TWN":"為了避免無辜的人被傷害，我能出的最好的辦法就是協助她防止出現更多死傷。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야? 이 순박한 머저리는?","JPN":"何？　このピュアなおバカは。","ENG":"What a naive dummy.","TWN":"啊，好純樸的笨蛋。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다른 감옥으로 안내해. 머뭇거릴 여유 없다.","JPN":"他の監獄に案内しろ。グダグダしている暇はない。","ENG":"Lead the way to a different section. We have no time to stand idle.","TWN":"帶我去另一個監獄吧，時間不多了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"알겠습니다. 하지만 이번엔 최대한 덜 부수는 방향으로 가주시죠.","JPN":"わかりました。でも、今度はもう少し控えめに暴れてくださいね。","ENG":"All right. But I have to ask you to break fewer things this time.","TWN":"好吧，但這次請儘量少搞破壞。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건 확답 못해주겠군.","JPN":"それは保障できないな。","ENG":"I can't promise anything.","TWN":"這我不能答應。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"잠깐만.","JPN":"ちょっと待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나도 데려가.","JPN":"あたしも連れてってよ。","ENG":"Take me too.","TWN":"帶我一起走。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 왜 그래야 하지?","JPN":"なぜ私が？","ENG":"Why should I?","TWN":"我為什麼要這麼做？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"죄수라면 감옥을 나가고 싶어하는 게 당연하니까.","JPN":"囚人が監獄から出たがるのは当然でしょ。","ENG":"As a prisoner, of course I want to leave this place.","TWN":"一個囚犯想逃出監獄是很正常的。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"자력으로 나갈 수 있으면서 일부러 갇혀 있는 게 아니었나?","JPN":"自力で出られるくせに、好きで閉じ込められているのではなかったのか？","ENG":"Aren't you in here on purpose? Surely you can break out whenever you want to.","TWN":"你明明可以靠自己逃出去卻故意一直被關在這裡，不是嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"모든 인간이 댁처럼 감옥벽을 맨손으로 부수는 괴물은 아니거든?","JPN":"すべての人間があんたみたいに監獄の壁を素手で壊す化け物じゃないんだよ。","ENG":"Not everyone can break prison walls with their bare hands like you.","TWN":"你以為所有人都是像你這種能徒手破壞監獄牆的怪物嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그리고 내려가서 막아야 할 녀석이 있어. 당신네들 세계가 위험해질 수도 있다고.","JPN":"それに、降りて止めなきゃいけない奴がいる。あんたらの世界が危険になるかもしれない。","ENG":"Plus, there's someone I need to stop down there. Your world might be in danger.","TWN":"而且我要去阻止一個人，不然你們的世界會面臨危險。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 잘난 육익에 무슨 문제라도 생긴 모양이지?","JPN":"六翼に何か問題でも起きたようだな。","ENG":"I take it there's some trouble within Six Wings, then.","TWN":"是那了不起的六翼出現了什麼問題吧？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…쳇.","JPN":"……チッ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"우리 멤버 중 하나가 제멋대로 움직이고 있어.","JPN":"メンバーの一人が勝手な行動をしてるんだ。","ENG":"One of our members is acting on her own.","TWN":"我們內部一名成員失控了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어가 녀석을 의심하고 있긴 한데… 정체를 알아챈대도 녀석을 막긴 힘들 거야.","JPN":"シャレードのシニアが奴を疑ってはいるけど……正体がわかっても奴を止めることは難しい。","ENG":"Charade's Senior is suspicious of her, but... even if he figures out her identity, it won't be enough to stop her.","TWN":"查雷德的Senior在懷疑她……但就算查明了身分應該也沒辦法阻止她的。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나유빈이 모아 놓은 떨거지들 사이에 기어이 내분이 벌어졌군.","JPN":"イチノセ・カオルが集めた落ちこぼれの中で、内輪揉めが始まったわけか。","ENG":"Na Yubin's band of strays has internal conflict. Of course.","TWN":"羅瑜斌收攏的烏合之眾終究發生了內訌。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"문제가 된 건 한 명이야.","JPN":"問題児は一人だけだよ。","ENG":"There's only one who's the problem.","TWN":"出問題的只是一個人而已。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"애초에 그 여자는 예전부터 우리들 사이에서도 어디로 튈지 모르던 요주의 인물이었거든.","JPN":"そもそもあの女、昔からあたしたちの間でも要注意人物だったんだ。","ENG":"She was always considered the questionable one among us who could act up at any time.","TWN":"那個女人從一開始就是我們的重點觀察人物，做什麼都喜歡肆意而為。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서 내가 대장 지시로 뒤를 캐고 있었는데… 결과는 보다시피 이 꼴.","JPN":"それであたしが隊長の指示で調べてたんだけど……結果はこの様ってわけ。","ENG":"So I was investigating her as per Commander's orders, and... well, you can see how that ended up.","TWN":"於是我遵循隊長的指示追蹤了她的行蹤，結果……如你所見。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래서, 그 녀석의 이름이 뭐지?","JPN":"それで、そいつの名は？","ENG":"So, what's her name?","TWN":"她叫什麼名字？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스완.","JPN":"スワン。","ENG":"Swan.","TWN":"史旺。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저희들의 협력자 중엔 그런 이름으로 활동하던 멤버가 있습니다.","JPN":"僕たちの協力者の中に、その名前で活動していたメンバーがいます。","ENG":"There's someone who went by the name Swan among our collaborators.","TWN":"我們的合作者中有一個人曾經用過這個名字。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇게 말씀하셔도 전 알 턱이 없는 이름… 이라고 하기엔 TV에서 자주 듣던 배우의 이름이군요.","JPN":"知らない名前だ……と言いたいところですが、テレビでよく聞く女優の名前ですね。","ENG":"I'd say it's pointless to tell me that name, but... that's the name of an actress I heard often on TV.","TWN":"就算這麼說，我也從沒聽說過這個名字……不，似乎也是一個電視演員的名字。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 우연의 일치일 뿐인 동명이인이겠지만요.","JPN":"もちろん同姓同名の別人でしょうけど。","ENG":"I'm sure it's just a coincidence.","TWN":"應該只是巧合吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아뇨. 시윤 군이 알고 있는 그 대배우 스완이 맞을 겁니다.","JPN":"いいえ。その大女優、スワン本人ですよ。","ENG":"It's not. I'm pretty sure it's the same Swan you know of.","TWN":"不，很可能就是時雲所說的那著名演員史旺。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고, 그녀는 육익의 정보수집원으로서 우리에게 많은 도움을 주기도 했죠.","JPN":"そして、彼女は六翼の情報収集員として大変役立ってくれました。","ENG":"And, she's been very helpful as Six Wings's information source.","TWN":"情報員而且她作為六翼的情報員給我們提供了不少幫助。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런데 얼마전, 그녀를 감시하고 있던 에이미 양으로부터 연락이 두절됐어요.","JPN":"ですがこの前、彼女を監視していたエイミーさんからの連絡が途絶えたのです。","ENG":"However, we recently lost contact with Amy, who's been keeping an eye on her.","TWN":"但在不久之前，負責監視她的艾米與我們失去了聯繫。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저희는 그녀가 육익을 배반했다고 판단했습니다.","JPN":"僕たちは彼女が六翼を裏切ったと判断しました。","ENG":"We've come to the conclusion that she betrayed Six Wings.","TWN":"我們判斷她已經背叛了六翼。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"감시라… 그 표현은 애초에 스완이란 분을 같은 편으로 생각하지 않은 것처럼 들리는데요?","JPN":"監視か……その言い方だと、最初からスワンを味方だとは思っていなかったようですね。","ENG":"You've been keeping an eye on her...? Sounds like you never considered her an ally in the first place.","TWN":"監視……聽起來從一開始就沒有把史旺當作自己人？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 세상 모두가 후배님처럼 동료를 끔찍이 믿어준다면 참 좋겠지만…","JPN":"はは、この世のみんなが後輩さんみたいに仲間想いだとは限りませんから。","ENG":"Ha ha. It would be a perfect world if everyone trusted their colleagues like you do...","TWN":"哈哈，如果所有人都像你一樣信任同伴就好了，但是……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"각자 다른 이해로 뭉쳐진 집단에선 함부로 신뢰라는 걸 주면 안 되거든요.","JPN":"各々違う利害で集まった者たちです。むやみに信用するべきではありません。","ENG":"But you shouldn't give away your trust so easily to a group of people with different goals.","TWN":"為各自的利益聚在一起的團隊裡，不能給予對方太多信任。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"대장. 이렇게까지 정보를 줄 필요는 없지 않나요?","JPN":"隊長。ここまで情報を与える必要はないのでは？","ENG":"Commander. I don't think we need to give him this much information.","TWN":"隊長。沒必要提供這麼多情報吧？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"괜찮아요, 지수 씨.","JPN":"大丈夫ですよ、シノさん。","ENG":"It's all right, Jisoo.","TWN":"沒關係，智秀。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어차피 곧 만천하에 드러날 진실이니, 굳이 숨길 필요도 없잖아요?","JPN":"どうせすぐに明らかになる事実です。あえて隠す必要はありません。","ENG":"Soon, the whole world will know the truth. There's no need to hide it.","TWN":"反正真相已經大白，又何必遮遮掩掩呢？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"내부 사정을 이렇게 친절하게 알려주시니 참 감사한 일입니다만.","JPN":"内部の事情を親切に教えてもらって、とてもありがたいんですが……","ENG":"I'm very grateful for you telling me all about your internal affairs.","TWN":"謝謝你為我如此親切地說明內部情況。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마 저더러 육익의 배신자 분을 대신 잡아달라는 부탁이라도 하려는 건 아니겠죠?","JPN":"まさか、僕に六翼の裏切り者を捕まえてくれと、頼むつもりじゃないですよね？","ENG":"But you're not going to ask me to go after Six Wings' traitor for you, right?","TWN":"你該不會是想要拜託我替你去抓那個六翼的叛徒吧？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런 걸 부탁으로 할 만큼 뻔뻔한 사람은 아닙니다.","JPN":"僕はそんなことを頼むほど図々しい人間ではありませんよ。","ENG":"I'm not shameless enough to ask other people of that.","TWN":"我的臉皮還厚到要求你幫我這個忙。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"사실 시윤 군이 맡아줘야 할 진짜 중요한 일은 따로 있거든요.","JPN":"シリュウ君に担当してもらいたい、本当に重要なことは別にありますから。","ENG":"Actually, there's something more important I need you to take care of, Shiyoon.","TWN":"其實還有一個更重要的事情需要時雲來完成。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 역시 일말의 여지없이 뻔뻔하시군요.","JPN":"はは、やっぱり図々しいじゃないですか。","ENG":"Hah hah. You are, without a doubt, shameless.","TWN":"哈哈，你果然臉皮很厚。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이건 어디까지나 서로를 위한 제안입니다.","JPN":"これはあくまでもお互いのための提案です。","ENG":"This offer also interests you.","TWN":"這是一個對我們彼此都有利的提議。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"후배님이 나서지 않으면 지금까지 관리자님이 해낸 일들이 전부 허사로 돌아갈 수도 있을 테니까요.","JPN":"後輩さんが出ないと、今まで管理者さんが成し遂げてきたことがすべて無駄になるかもしれませんから。","ENG":"If you don't intervene, everything the Administrator has been doing might be in vain.","TWN":"如果你不幫忙，管理者一直以來的努力都會泡湯的。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"우리 모두, 그런 결말은 바라지 않잖아요?","JPN":"僕たちみんな、そんな結末は望んでいないでしょう？","ENG":"And we wouldn't want that, would we?","TWN":"我們都不想看到這樣的結局，不是嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};